10	final class JSONReader<T: Decodable>: Sequence, IteratorProtocol {
11	    
12	    private lazy var decoder: JSONDecoder = {
13	        let decoder = JSONDecoder()
14	        return decoder
15	    }()
16	
17	    private let fileHandle: FileHandle
18	    private var buffer: Data
19	    private let chunkSize: Int = 1024 * 1024 // 1 MB буфер
20	    private let maxLineSize: Int = 10 * 1024 * 1024 // Максимальный размер строки (10 MB)
21	    private var isEOF: Bool = false
22	    
23	    init(url: URL) throws {
24	        self.fileHandle = try FileHandle(forReadingFrom: url)
25	        self.buffer = Data(capacity: chunkSize) // Инициализируем буфер с начальной ёмкостью
26	    }
27	        
28	    func next() -> T? {
29	        var currentLine = Data()
30	        
31	        while !isEOF {
32	            // Если буфер пуст, читаем новый кусок данных
33	            if buffer.isEmpty {
34	                do {
35	                    if let chunk = try fileHandle.read(upToCount: chunkSize), !chunk.isEmpty {
36	                        buffer.append(chunk)
37	                    } else {
38	                        isEOF = true
39	                        // Если есть накопленные данные, пытаемся декодировать
40	                        if !currentLine.isEmpty {
41	                            return try? decodeLine(currentLine)
42	                        }
43	                        return nil
44	                    }
45	                } catch {
46	                    Log.error(error)
47	                    return nil
48	                }
49	            }
50	            
51	            // Ищем разделитель в буфере
52	            if let range = buffer.range(of: JSONWriter.Consts.delimiter) {
53	                // Добавляем данные до разделителя в currentLine
54	                let lineData = buffer.subdata(in: 0..<range.lowerBound)
55	                
56	                // Проверяем, не превышает ли размер строки допустимый лимит
57	                guard currentLine.count + lineData.count <= maxLineSize else {
58	                    Log.error("Line size exceeds limit of \(maxLineSize) bytes")
59	                    buffer = Data() // Очищаем буфер
60	                    return nil // Пропускаем слишком большую строку
61	                }
62	                
63	                currentLine.append(lineData)
64	                // Удаляем обработанные данные и разделитель из буфера
65	                buffer = buffer.subdata(in: range.upperBound..<buffer.count)
66	                
67	                // Пытаемся декодировать строку
68	                if let result = try? decodeLine(currentLine) {
69	                    return result
70	                }
71	                currentLine = Data() // Очищаем, если декодирование не удалось
72	            } else {
73	                // Проверяем, не превышает ли размер строки допустимый лимит
74	                guard currentLine.count + buffer.count <= maxLineSize else {
75	                    Log.error("Line size exceeds limit of \(maxLineSize) bytes")
76	                    buffer = Data() // Очищаем буфер
77	                    return nil // Пропускаем слишком большую строку
78	                }
79	                
80	                // Переносим данные из буфера в currentLine
81	                currentLine.append(buffer)
82	                buffer = Data()
83	            }
84	        }
