21	protocol DatabaseMigrationManager {
22	    func migrateDatabaseIfNeeded() async
23	    func importDatabase(databaseUrl: URL) async -> Bool
24	}
25	
26	final class DatabaseMigrationManagerImpl: DatabaseMigrationManager {
27	    
28	    @LazyInjected(\.backupCoordinator) private var backupCoordinator
29	    @LazyInjected(\.migration) private var migration
30	    @LazyInjected(\.databaseBackupFileManager) private var databaseBackupFileManager
31	    
32	    func migrateDatabaseIfNeeded() async {
33	        var migrationDataBaseUrl: URL?
34	        // Проверяем есть ли упавшая база
35	        if let databaseUrl = databaseBackupFileManager.brokenDatabase() {
36	            await migration.setState(.migrating)
37	            let success = await backupCoordinator.storeFromDatabase(from: databaseUrl)
38	            if !success {
39	                migrationDataBaseUrl = try? databaseBackupFileManager.zipDB()
40	            }
41	            // Удаление после экспорта, если успешно, то она больше не нужна, если нет, то база архиваируеся в zip
42	            removeDatabaseSafely(.backup)
43	        }
44	        
45	        await backupCoordinator.restore()
46	        
47	        let finalState: Migration.State = {
48	            if let url = migrationDataBaseUrl {
49	                return .failure(databaseURL: url)
50	            } else {
51	                return .ready
52	            }
53	        }()
54	        
55	        await migration.setState(finalState)
56	    }
57	    
58	    func importDatabase(databaseUrl: URL) async -> Bool {
59	        defer { removeDatabaseSafely(.import) }
60	        let success = await backupCoordinator.storeFromDatabase(from: databaseUrl)
61	        if success {
62	            do {
63	                try await backupCoordinator.clearAllObjectsDB()
64	                await backupCoordinator.restore()
65	            }
66	            catch {
67	                return false
68	            }
69	        }
70	        return success
71	    }
72	    
73	    private func removeDatabaseSafely(_ role: DatabaseBackupTarget) {
74	        do {
75	            try databaseBackupFileManager.removeDatabase(database: role)
76	        } catch {
77	            Log.error(error)
78	        }
79	    }
80	}
